import { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, AlignmentType, ShadingType, Header, LevelFormat } from 'docx';

/**
 * Genera y descarga un .docx usando la librería 'docx'.
 * Incluye definiciones de numbering para viñetas, números y letras.
 */
export async function generateWordDocument(documentData = {}, procedureData = []) {
  try {
    const formattedDate = formatDate(documentData.headerConfig?.fecha);

    const doc = new Document({
      styles: {
        paragraphStyles: [
          { id: 'Heading1', name: 'Heading 1', basedOn: 'Normal', quickFormat: true },
        ],
      },
      numbering: {
        config: [
          {
            reference: 'bullet-numbering',
            levels: [
              { level: 0, format: LevelFormat.BULLET, text: '•', alignment: 'left' },
            ],
          },
          {
            reference: 'decimal-numbering',
            levels: [
              { level: 0, format: LevelFormat.DECIMAL, text: '%1.', alignment: 'left' },
            ],
          },
          {
            reference: 'letter-numbering',
            levels: [
              { level: 0, format: LevelFormat.LOWER_LETTER, text: '%1.', alignment: 'left' },
            ],
          },
        ],
      },
    });

    const children = [];

    // Header simplified (kept as content paragraphs; for complex header keep createHeaderTable)
    children.push(
      new Paragraph({ text: documentData.headerConfig?.policyName || 'PROCEDIMIENTO', heading: HeadingLevel.HEADING_1 }),
      new Paragraph({ text: `Código: ${documentData.headerConfig?.codigo || 'XX-P-XXX-#'}` }),
      new Paragraph({ text: `Área: ${documentData.headerConfig?.area || 'Área responsable'}` }),
      new Paragraph({ text: `Unidad: ${documentData.headerConfig?.unidad || 'Unidad específica'}` }),
      new Paragraph({ text: `Revisión: ${documentData.headerConfig?.revision || '(1)'}` }),
      new Paragraph({ text: `Fecha: ${formattedDate}` })
    );

    // Secciones
    children.push(new Paragraph({ text: '1. Objetivo o Propósito', heading: HeadingLevel.HEADING_1, spacing: { before: 400, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.objetivo || 'Contenido pendiente de completar.'));

    children.push(new Paragraph({ text: '2. Alcance', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.alcance || 'Contenido pendiente de completar.'));

    children.push(new Paragraph({ text: '3. Responsabilidades', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.responsabilidades || 'Contenido pendiente de completar.'));

    children.push(new Paragraph({ text: '4. Normativa', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.normativa || 'Contenido pendiente de completar.'));

    // Procedimiento (tabla)
    children.push(new Paragraph({ text: '5. Procedimiento', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(createProcedureTable(procedureData));

    children.push(new Paragraph({ text: '6. Anexos', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.anexos || 'Contenido pendiente de completar.'));

    children.push(new Paragraph({ text: '7. Términos y Referencias', heading: HeadingLevel.HEADING_1, spacing: { before: 240, after: 120 } }));
    children.push(...parseHtmlToParagraphs(documentData.terminos || 'Contenido pendiente de completar.'));

    doc.addSection({
      properties: {
        page: {
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
      headers: {
        default: new Header({
          // Si quieres un header con tabla, reemplaza por createHeaderTable(...)
          children: [new Paragraph({ text: documentData.headerConfig?.manualName || 'Manual de Políticas y Procedimientos', alignment: AlignmentType.CENTER })],
        }),
      },
      children,
    });

    const blob = await Packer.toBlob(doc);
    const fileName = `${documentData.headerConfig?.policyName || 'Procedimiento'}.docx`;

    if (window.navigator && window.navigator.msSaveOrOpenBlob) {
      window.navigator.msSaveOrOpenBlob(blob, fileName);
    } else {
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      link.style.display = 'none';
      document.body.appendChild(link);
      link.click();
      setTimeout(() => {
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      }, 150);
    }

    return true;
  } catch (error) {
    console.error('Error generando documento Word:', error);
    throw new Error(`Error al generar el documento: ${error.message}`);
  }
}

/* ---------------- Helpers ---------------- */

function formatDate(dateInput) {
  const d = dateInput ? new Date(dateInput) : new Date();
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  return `${day}-${month}-${year}`;
}

function safeText(value) {
  if (value == null) return '';
  return String(value).replace(/\s+/g, ' ').trim();
}

/**
 * Parsea HTML simple (p, ul, ol, li, br) a Paragraphs de docx.
 * Asegura usar numbering.reference igual a la configuración del Document.
 */
function parseHtmlToParagraphs(html = '') {
  const paragraphs = [];
  if (!html) return paragraphs;

  try {
    // Si no contiene tags, dividir por saltos de línea
    if (!html.includes('<') && !html.includes('>')) {
      const lines = String(html).split(/\n+/).map(s => safeText(s)).filter(Boolean);
      lines.forEach(line => paragraphs.push(new Paragraph({ children: [new TextRun(line)], spacing: { after: 120 } })));
      return paragraphs;
    }

    const parser = new DOMParser();
    const doc = parser.parseFromString(`<div>${html}</div>`, 'text/html');
    const root = doc.body.firstElementChild || doc.body;

    root.childNodes.forEach(node => {
      if (node.nodeType !== Node.ELEMENT_NODE) {
        const text = safeText(node.textContent);
        if (text) paragraphs.push(new Paragraph({ children: [new TextRun(text)], spacing: { after: 120 } }));
        return;
      }

      const tag = node.tagName.toLowerCase();

      if (tag === 'p') {
        const text = safeText(node.textContent);
        if (text) paragraphs.push(new Paragraph({ children: [new TextRun(text)], spacing: { after: 120 } }));
      } else if (tag === 'ul' || tag === 'ol') {
        const isOrdered = tag === 'ol';
        const outer = node.outerHTML || '';
        const isLetter = /data-type\s*=\s*["']letter["']/i.test(outer);
        const numberingRef = isLetter ? 'letter-numbering' : (isOrdered ? 'decimal-numbering' : 'bullet-numbering');

        node.querySelectorAll('li').forEach(li => {
          const liText = safeText(li.textContent);
          if (!liText) return;
          paragraphs.push(new Paragraph({
            children: [new TextRun(liText)],
            numbering: { reference: numberingRef, level: 0 },
            spacing: { after: 80 },
          }));
        });
      } else if (tag === 'br') {
        paragraphs.push(new Paragraph({ text: '' }));
      } else {
        const text = safeText(node.textContent);
        if (text) paragraphs.push(new Paragraph({ children: [new TextRun(text)], spacing: { after: 120 } }));
      }
    });
  } catch (e) {
    // Fallback: limpiar tags y dividir por saltos
    const cleaned = String(html).replace(/<br\s*\/?>/gi, '\n').replace(/<[^>]+>/g, '').replace(/&nbsp;/g, ' ').trim();
    if (cleaned) {
      cleaned.split(/\n+/).map(s => safeText(s)).filter(Boolean).forEach(t => {
        paragraphs.push(new Paragraph({ children: [new TextRun(t)], spacing: { after: 120 } }));
      });
    }
  }

  if (paragraphs.length === 0) paragraphs.push(new Paragraph({ text: '' }));
  return paragraphs;
}

/**
 * Crea una tabla para el procedimiento (uso de docx Table)
 */
function createProcedureTable(data = []) {
  if (!data || data.length === 0) {
    return new Paragraph({ text: 'No se ha definido el procedimiento.', spacing: { after: 120 } });
  }

  const headerRow = new TableRow({
    children: [
      new TableCell({
        width: { size: 1700, type: WidthType.DXA },
        shading: { fill: 'D9D9D9', type: ShadingType.CLEAR },
        children: [new Paragraph({ children: [new TextRun({ text: '(#)', bold: true })], spacing: { before: 0, after: 0 } })],
      }),
      new TableCell({
        width: { size: 2800, type: WidthType.DXA },
        shading: { fill: 'D9D9D9', type: ShadingType.CLEAR },
        children: [new Paragraph({ children: [new TextRun({ text: '(Quien)', bold: true })], spacing: { before: 0, after: 0 } })],
      }),
      new TableCell({
        width: { size: 6800, type: WidthType.DXA },
        shading: { fill: 'D9D9D9', type: ShadingType.CLEAR },
        children: [new Paragraph({ children: [new TextRun({ text: '(Actividad)', bold: true })], spacing: { before: 0, after: 0 } })],
      }),
    ],
  });

  const rows = [headerRow];

  data.forEach(row => {
    let number = safeText(row.number || '');
    if (number) {
      if (!number.includes('.') && !isNaN(number)) number = `5.${number}`;
      else if (!number.startsWith('5.')) {
        const segs = number.split('.');
        if (segs.every(s => /^\d+$/.test(s.trim()))) number = `5.${number}`;
      }
    }

    const who = safeText(row.who || '');
    const activity = safeText(row.activity || '');
    const level = safeText(row.level || '');
    const bg = getBackgroundColor(level);

    rows.push(new TableRow({
      children: [
        new TableCell({
          children: [new Paragraph({ children: [new TextRun(number)] })],
          shading: bg ? { fill: bg, type: ShadingType.CLEAR } : undefined,
        }),
        new TableCell({
          children: [new Paragraph({ children: [new TextRun(who)] })],
          shading: bg ? { fill: bg, type: ShadingType.CLEAR } : undefined,
        }),
        new TableCell({
          children: [new Paragraph({ children: [new TextRun(activity)] })],
          shading: bg ? { fill: bg, type: ShadingType.CLEAR } : undefined,
        }),
      ],
    }));
  });

  return new Table({
    rows,
    width: { size: 100, type: WidthType.PERCENTAGE },
  });
}

function getBackgroundColor(level) {
  const colors = {
    sub: 'E8F5E8',
    section: 'E3F2FD',
    question: 'FFF3CD',
    alternative: 'D1ECF1',
    end: 'D4EDDA',
  };
  return colors[level] || '';
}
